// Функция для экранирования значений Google Sheets
function escapeGoogleSheetValue(value) {
  if (typeof value !== 'string') return value;
  const firstChar = value.charAt(0);
  if (firstChar === '=' || firstChar === '+' || firstChar === '-' || firstChar === '@') {
    return "'" + value;
  }
  return value;
}

// Преобразуем directions из массива в читаемый текст
if (Array.isArray(items[0].json.directions)) {
  items[0].json.directions_readable = escapeGoogleSheetValue(
    items[0].json.directions.join(', ')
  );
}

// Преобразуем schedule — новые русские значения из формы
const scheduleMap = {
  'Будни: Вечер (18:30 - 20:15)': 'Будни (Пн-Пт): Вечер 18:30-20:15',
  'Будни: Поздний вечер (20:15 - 22:00)': 'Будни (Пн-Пт): Поздний вечер 20:15-22:00',
  'Выходные: Утро (09:00 - 13:00)': 'Выходные (Сб-Вс): Утро 09:00-13:00',
  'Выходные: День (13:00 - 17:00)': 'Выходные (Сб-Вс): День 13:00-17:00',
  'Выходные: Вечер (17:00 - 21:00)': 'Выходные (Сб-Вс): Вечер 17:00-21:00',
  'Любой день и время': 'Готова в любое время'
};

if (items[0].json.schedule) {
  const schedules = typeof items[0].json.schedule === 'string' 
    ? items[0].json.schedule.split(', ').filter(Boolean)
    : [items[0].json.schedule];
  items[0].json.schedule_readable = escapeGoogleSheetValue(
    schedules.map(v => scheduleMap[v.trim()] || v).join(', ')
  );
}

return items;
